mapper.sql:
WHERE permission_user.id is not NULL
AND permission_user.deleted = #{deleted}
AND permission_user.created_at >= CONCAT(#{sdate}, ' 00:00:00')
AND CONCAT(#{fdate}, ' 23:59:59') >= permission_user.created_at
AND permission_user.permission_id = #{permissionId}
AND permission_user.user_id = #{userId}
